features.snippet:
interface my_interface #(
  parameter ADDR = 32,
  parameter DATA = 64
);
logic request;
logic [ADDR-1:0] addr_;
logic [DATA-1:0] data_;
modport slave(
 input request,
 input addr_,
 output data
);
modport master(
 output request,
 output addr_,
 input data
);
endinterface

module MY_TOP (
  input clk_a,
  my_interface.master if_m[NUM - 1:0],
  my_interface.slave if_s[NUM - 1:0]
);
endmodule
